// frontend/src/pages/History.jsx — Member 5
// Transaction History + Token Balance

// Professional & Minimal — Linear-inspired dark theme (fixed visibility)

import { useState, useEffect } from "react";
import { getCrowdfundingContract, getRewardTokenContract, fromWei } from "../utils/contracts";
import addresses from "../utils/addresses.json";
import CrowdfundingABI from "../utils/abi/Crowdfunding.json";
import { ethers } from "ethers";

const TYPES = {
  "Contribution":  { color: "#7C71F2", icon: "↑" },
  "Withdrawal":    { color: "#34D399", icon: "↓" },
  "Refund":        { color: "#FBBF24", icon: "↩" },
  "Tokens Minted": { color: "#F472B6", icon: "✦" },
};

export default function History({ user }) {
  const [tokenBalance, setTokenBalance] = useState("0");
  const [history, setHistory]           = useState([]);
  const [loading, setLoading]           = useState(false);
  const [error, setError]               = useState("");
  const [filter, setFilter]             = useState("All");
  const [copied, setCopied]             = useState(null);

  useEffect(() => { loadTokenBalance(); loadHistory(); }, []);

  async function loadTokenBalance() {
    try {
      const contract = await getRewardTokenContract();
      const bal = await contract.getBalance(user.address);
      setTokenBalance(ethers.formatUnits(bal, 18));
    } catch (err) { console.error(err); }
  }

  async function loadHistory() {
    try {
      setLoading(true);
      const provider = new ethers.BrowserProvider(window.ethereum);
      const contract = new ethers.Contract(addresses.Crowdfunding, CrowdfundingABI.abi, provider);
      const [funded, withdrawn, refunded, minted] = await Promise.all([
        contract.queryFilter(contract.filters.Funded(null, user.address)),
        contract.queryFilter(contract.filters.Withdrawn(null, user.address)),
        contract.queryFilter(contract.filters.Refunded(null, user.address)),
        contract.queryFilter(contract.filters.TokensMinted(null, user.address)),
      ]);
      const entries = [
        ...funded.map(e   => ({ type: "Contribution",  campaignId: e.args.campaignId.toString(), amount: fromWei(e.args.amount),        unit: "ETH", txHash: e.transactionHash, block: e.blockNumber })),
        ...withdrawn.map(e => ({ type: "Withdrawal",    campaignId: e.args.campaignId.toString(), amount: fromWei(e.args.amount),        unit: "ETH", txHash: e.transactionHash, block: e.blockNumber })),
        ...refunded.map(e  => ({ type: "Refund",        campaignId: e.args.campaignId.toString(), amount: fromWei(e.args.amount),        unit: "ETH", txHash: e.transactionHash, block: e.blockNumber })),
        ...minted.map(e    => ({ type: "Tokens Minted", campaignId: e.args.campaignId.toString(), amount: e.args.tokens.toString(),      unit: "BTK", txHash: e.transactionHash, block: e.blockNumber })),
      ];
      entries.sort((a, b) => b.block - a.block);
      setHistory(entries);
    } catch (err) { setError(err.message); }
    finally { setLoading(false); }
  }

  function copyHash(hash) {
    navigator.clipboard.writeText(hash);
    setCopied(hash);
    setTimeout(() => setCopied(null), 1500);
  }

  const FILTERS   = ["All", ...Object.keys(TYPES)];
  const filtered  = filter === "All" ? history : history.filter(h => h.type === filter);
  const totalETH  = history
    .filter(h => h.unit === "ETH" && h.type === "Contribution")
    .reduce((s, h) => s + parseFloat(h.amount), 0)
    .toFixed(3);

  return (
    <div style={s.root}>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Inter:wght@300;400;500;600&display=swap');
        @keyframes fadeIn { from{opacity:0;transform:translateY(5px)} to{opacity:1;transform:translateY(0)} }
        @keyframes spin   { to{transform:rotate(360deg)} }
        .tx-row:hover   { background: #141416 !important; }
        .filter-pill:hover { border-color: #2C2C2E !important; color: #A1A1AA !important; }
        .copy-btn:hover { color: #fff !important; }
        .refresh-btn:hover { border-color: #3C3C3E !important; color: #A1A1AA !important; }
      `}</style>

      {/* ── Page Header ── */}
      <div style={s.topBar}>
        <div>
          <h1 style={s.title}>Activity</h1>
          <p style={s.subtitle}>
            <span style={s.dot} /> {user.address?.slice(0,6)}...{user.address?.slice(-4)}
          </p>
        </div>
        <button className="refresh-btn"
          onClick={() => { loadTokenBalance(); loadHistory(); }}
          style={s.refreshBtn}>
          ↻ Refresh
        </button>
      </div>

      {/* ── Metric Cards ── */}
      <div style={s.metricsRow}>

        {/* BTK Balance */}
        <div style={s.metricCard}>
          <div style={s.metricTop}>
            <p style={s.metricLabel}>BonusToken Balance</p>
            <span style={{ ...s.metricBadge, background: "#F472B615", color: "#F472B6" }}>BTK</span>
          </div>
          <p style={{ ...s.metricVal, color: "#F472B6" }}>
            {Number(tokenBalance).toFixed(2)}
            <span style={s.metricUnit}> BTK</span>
          </p>
          <div style={{ ...s.metricTrack, background: "#F472B615" }}>
            <div style={{ ...s.metricFill, width: Math.min(Number(tokenBalance) * 10, 100) + "%", background: "#F472B6" }} />
          </div>
        </div>

        {/* Total Contributed */}
        <div style={s.metricCard}>
          <div style={s.metricTop}>
            <p style={s.metricLabel}>Total Contributed</p>
            <span style={{ ...s.metricBadge, background: "#7C71F215", color: "#7C71F2" }}>ETH</span>
          </div>
          <p style={{ ...s.metricVal, color: "#7C71F2" }}>
            {totalETH}
            <span style={s.metricUnit}> ETH</span>
          </p>
          <div style={{ ...s.metricTrack, background: "#7C71F215" }}>
            <div style={{ ...s.metricFill, width: Math.min(parseFloat(totalETH) * 10, 100) + "%", background: "#7C71F2" }} />
          </div>
        </div>

        {/* Total Transactions */}
        <div style={s.metricCard}>
          <div style={s.metricTop}>
            <p style={s.metricLabel}>Total Transactions</p>
            <span style={{ ...s.metricBadge, background: "#34D39915", color: "#34D399" }}>ALL</span>
          </div>
          <p style={{ ...s.metricVal, color: "#34D399" }}>
            {history.length}
            <span style={s.metricUnit}> txns</span>
          </p>
          <div style={{ display: "flex", gap: 12, marginTop: 10, flexWrap: "wrap" }}>
            {Object.entries(TYPES).map(([type, cfg]) => {
              const count = history.filter(h => h.type === type).length;
              return count > 0 ? (
                <span key={type} style={{ display: "flex", alignItems: "center", gap: 5, fontSize: 11, color: "#636366" }}>
                  <span style={{ width: 5, height: 5, borderRadius: "50%", background: cfg.color, display: "inline-block" }} />
                  {type.split(" ")[0]} · {count}
                </span>
              ) : null;
            })}
          </div>
        </div>

      </div>

      {/* ── Filter Pills ── */}
      <div style={s.filterRow}>
        {FILTERS.map(f => {
          const count  = f === "All" ? history.length : history.filter(h => h.type === f).length;
          const active = filter === f;
          const color  = f === "All" ? "#7C71F2" : TYPES[f]?.color;
          return (
            <button key={f} className="filter-pill"
              onClick={() => setFilter(f)}
              style={{
                ...s.pill,
                ...(active ? {
                  background: color + "15",
                  border: "1px solid " + color + "35",
                  color,
                } : {}),
              }}>
              {f !== "All" && (
                <span style={{
                  width: 5, height: 5, borderRadius: "50%",
                  background: active ? color : "#3A3A3D",
                  display: "inline-block", flexShrink: 0,
                }} />
              )}
              {f}
              <span style={{
                ...s.pillCount,
                ...(active ? { background: color + "20", color } : {}),
              }}>
                {count}
              </span>
            </button>
          );
        })}
      </div>

      {/* ── Transaction Table ── */}
      <div style={s.tableCard}>

        {/* Table Header */}
        <div style={s.tableHeader}>
          <span style={{ flex: 2.2 }}>TYPE</span>
          <span style={{ flex: 1.5 }}>CAMPAIGN</span>
          <span style={{ flex: 1.2 }}>AMOUNT</span>
          <span style={{ flex: 0.8 }}>BLOCK</span>
          <span style={{ flex: 2 }}>TX HASH</span>
        </div>

        {/* Loading State */}
        {loading && (
          <div style={s.centerState}>
            <div style={s.spinner} />
            <p style={{ color: "#48484A", fontSize: 13, marginTop: 14 }}>Fetching on-chain data...</p>
          </div>
        )}

        {/* Error State */}
        {error && !loading && (
          <div style={s.centerState}>
            <p style={{ fontSize: 20, marginBottom: 8 }}>⚠</p>
            <p style={{ color: "#F87171", fontSize: 13 }}>{error}</p>
          </div>
        )}

        {/* Empty State */}
        {!loading && !error && filtered.length === 0 && (
          <div style={s.centerState}>
            <div style={s.emptyCircle}>◈</div>
            <p style={{ color: "#636366", fontSize: 14, margin: "12px 0 4px", fontWeight: 500 }}>
              No transactions found
            </p>
            <p style={{ color: "#3A3A3D", fontSize: 12, margin: 0 }}>
              Contribute to a campaign to see your activity here
            </p>
          </div>
        )}

        {/* Rows */}
        {!loading && !error && filtered.map((row, i) => {
          const cfg = TYPES[row.type];
          return (
            <div key={i} className="tx-row"
              style={{ ...s.tableRow, animationDelay: (i * 0.05) + "s" }}>

              {/* Type */}
              <div style={{ flex: 2.2, display: "flex", alignItems: "center", gap: 10 }}>
                <div style={{ ...s.iconBox, background: cfg.color + "15", color: cfg.color }}>
                  {cfg.icon}
                </div>
                <div>
                  <p style={{ margin: 0, fontSize: 13, color: "#D1D1D6", fontWeight: 500 }}>{row.type}</p>
                </div>
              </div>

              {/* Campaign */}
              <div style={{ flex: 1.5 }}>
                <span style={s.campaignTag}>Campaign #{row.campaignId}</span>
              </div>

              {/* Amount */}
              <div style={{ flex: 1.2, display: "flex", alignItems: "baseline", gap: 4 }}>
                <span style={{ fontSize: 15, fontWeight: 600, color: cfg.color }}>{row.amount}</span>
                <span style={{ fontSize: 11, color: "#48484A", fontWeight: 500 }}>{row.unit}</span>
              </div>

              {/* Block */}
              <div style={{ flex: 0.8 }}>
                <span style={s.blockTag}>#{row.block}</span>
              </div>

              {/* Tx Hash */}
              <div style={{ flex: 2, display: "flex", alignItems: "center", gap: 8 }}>
                <span style={s.hashText}>
                  {row.txHash.slice(0, 10)}...{row.txHash.slice(-6)}
                </span>
                <button className="copy-btn"
                  onClick={() => copyHash(row.txHash)}
                  title="Copy full hash"
                  style={{ ...s.copyBtn, color: copied === row.txHash ? "#34D399" : "#3A3A3D" }}>
                  {copied === row.txHash ? "✓" : "⎘"}
                </button>
              </div>
            </div>
          );
        })}

        {/* Footer */}
        {!loading && filtered.length > 0 && (
          <div style={s.tableFooter}>
            Showing {filtered.length} of {history.length} transactions
          </div>
        )}
      </div>
    </div>
  );
}

const s = {
  root: {
    maxWidth: 960,
    margin: "0 auto",
    padding: "36px 28px",
    fontFamily: "'Inter', -apple-system, BlinkMacSystemFont, sans-serif",
  },

  // Header
  topBar: {
    display: "flex", justifyContent: "space-between",
    alignItems: "flex-start", marginBottom: 32,
  },
  title: {
