    padding: "7px 14px", background: "#111113",
    border: "1px solid #2A2A2D", borderRadius: 8,
    color: "#636366", fontSize: 12, fontWeight: 500,
    cursor: "pointer", fontFamily: "inherit", transition: "all 0.15s",
  },

  // Metric Cards
  metricsRow: {
    display: "grid", gridTemplateColumns: "repeat(3,1fr)",
    gap: 12, marginBottom: 24,
  },
  metricCard: {
    background: "#111113", border: "1px solid #1E1E22",
    borderRadius: 12, padding: "20px 22px",
  },
  metricTop: {
    display: "flex", justifyContent: "space-between",
    alignItems: "center", marginBottom: 10,
  },
  metricLabel: {
    margin: 0, fontSize: 11, color: "#48484A",
    textTransform: "uppercase", letterSpacing: "0.8px", fontWeight: 600,
  },
  metricBadge: {
    fontSize: 10, fontWeight: 700, padding: "2px 7px",
    borderRadius: 99, letterSpacing: "0.5px",
  },
  metricVal: {
    margin: "0 0 14px", fontSize: 28, fontWeight: 700,
    letterSpacing: "-0.6px", lineHeight: 1,
  },
  metricUnit: { fontSize: 14, fontWeight: 400, opacity: 0.5 },
  metricTrack: { height: 3, borderRadius: 99, overflow: "hidden" },
  metricFill:  { height: "100%", borderRadius: 99, transition: "width 0.8s ease" },

  // Filter Pills
